ToolUse.name:
node -e "
const rs = require('./src/shared/room-state.js');
const vm = require('./src/shared/video-match.js');
console.log('STATES keys:', Object.keys(rs.STATES).join(', '));
console.log('TRANSITIONS keys:', Object.keys(rs.TRANSITIONS).join(', '));
const sm = new rs.RoomStateMachine();
console.log('initial state:', sm.state);
console.log('canSync initial:', sm.canSync());
sm.setState(rs.STATES.CONNECTING);
sm.setState(rs.STATES.IN_ROOM_NO_VIDEO);
sm.setState(rs.STATES.IN_ROOM_WAITING_PEER_VIDEO);
sm.setState(rs.STATES.IN_ROOM_SYNCED);
console.log('after transitions:', sm.state, 'canSync:', sm.canSync());
// mismatch
sm.setState(rs.STATES.IN_ROOM_MISMATCH);
console.log('mismatch canSync:', sm.canSync());
// back to synced
sm.setState(rs.STATES.IN_ROOM_SYNCED);
console.log('back to synced canSync:', sm.canSync());
// exit
sm.setState(rs.STATES.NO_ROOM);
console.log('exit:', sm.state, 'canSync:', sm.canSync());
"

