ToolUse.name:
node -e "
const vm = require('./src/shared/video-match.js');
// Test 1: URL match
console.log('URL match:', vm.videosMatch({url:'https://x.com/a.mp4',loaded:true},{url:'https://x.com/a.mp4',loaded:true}));
// Test 2: fileName match (local file)
console.log('fileName match:', vm.videosMatch({fileName:'a.mp4',duration:100,loaded:true},{fileName:'a.mp4',duration:100,loaded:true}));
// Test 3: duration match (no fileName, no url)
console.log('duration match:', vm.videosMatch({duration:100,loaded:true},{duration:100.5,loaded:true}));
// Test 4: mismatch
console.log('mismatch URL:', vm.videosMatch({url:'https://x.com/a.mp4',duration:100,loaded:true},{url:'https://x.com/b.mp4',duration:100,loaded:true}));
// Test 5: empty info
console.log('empty info:', vm.videosMatch({loaded:false},{loaded:true}));
// Test 6: normalizeUrl
console.log('normalize url:', vm.normalizeUrl('https://x.com/a.mp4#t=10'));
// Test 7: describeVideo
const v = {src:'https://x.com/a.mp4', duration: 100};
console.log('describeVideo:', vm.describeVideo(v, '加载中: a.mp4'));
const v2 = {src:'blob:http://localhost/abc', duration: 100};
console.log('describeVideo blob:', vm.describeVideo(v2, '本地: mymovie.mp4'));
"

