ToolUse.name:
node -e "
const { RoomStateMachine, STATES } = require('./src/shared/room-state.js');
const { videosMatch, describeVideo, emptyVideoInfo } = require('./src/shared/video-match.js');

console.log('=== 清单 1: 状态机 6 态验证 ===');
const sm = new RoomStateMachine();
const states = Object.values(STATES);
console.log('6 状态:', states.join(', '));
console.log('数量:', states.length, '(期望 6)');

console.log('\n=== 清单 2.1: 加载视频前能创建房间 (startSession 不强制 video) ===');
// 验证 startSession 不调 ensureVideoReady — 通过 grep
const fs = require('fs');
const app = fs.readFileSync('src/client/app.js', 'utf8');
console.log('ensureVideoReady 调用数:', (app.match(/ensureVideoReady\(\)/g) || []).length, '(期望 0 — 已删除)');
console.log('startSession 定义:', app.includes('function startSession'));
console.log('startSession 内 ensureVideoReady:', /function startSession[\s\S]{0,500}ensureVideoReady/.test(app) ? '是' : '否');

console.log('\n=== 清单 2.3: 退出房间后视频状态保留 (video 元素不清空) ===');
const exitRoomBlock = app.match(/function exitRoom\(\)\s*{[\s\S]{0,500}/);
console.log('exitRoom 调 video.removeAttribute?:', /exitRoom[\s\S]{0,500}video\.removeAttribute/.test(app));
console.log('exitRoom 调 video.load?:', /exitRoom[\s\S]{0,500}video\.load\(\)/.test(app));
console.log('exitRoom 调 video.src=?:', /exitRoom[\s\S]{0,500}video\.src\s*=/.test(app));
console.log('exitRoom 设 connMgr=null:', /exitRoom[\s\S]{0,500}connMgr\s*=\s*null/.test(app));
console.log('exitRoom setState(NO_ROOM):', /exitRoom[\s\S]{0,500}setState\(.*NO_ROOM/.test(app));

console.log('\n=== 清单 3.4: 匹配算法 3 种情况 ===');
console.log('URL 匹配:', videosMatch({url:'https://a.com/x.mp4',loaded:true},{url:'https://a.com/x.mp4',loaded:true}));
console.log('fileName 匹配:', videosMatch({fileName:'x.mp4',duration:100,loaded:true},{fileName:'x.mp4',duration:100,loaded:true}));
console.log('duration 匹配 (100 vs 100.5):', videosMatch({duration:100,loaded:true},{duration:100.5,loaded:true}));
console.log('任一不匹配:', videosMatch({url:'https://a.com/x.mp4',loaded:true},{fileName:'x.mp4',duration:100,loaded:true}));

console.log('\n=== 清单 3.5: 不匹配时 canSync 关闭 ===');
sm._forceState(STATES.IN_ROOM_MISMATCH);
console.log('IN_ROOM_MISMATCH canSync:', sm.canSync(), '(期望 false)');

console.log('\n=== 清单 4: mismatch-warning UI ===');
const css = fs.readFileSync('src/client/style.css', 'utf8');
console.log('mismatch-warning class:', css.includes('.mismatch-warning'));
console.log('mismatch-pulse 动画:', css.includes('mismatch-pulse'));
console.log('transition 平滑:', css.includes('transition: all 0.2s ease'));

console.log('\n=== 清单 5: 单测覆盖 ===');
console.log('room-state.test.js 测例数: ~32');
console.log('video-match.test.js 测例数: ~28');
console.log('npm test 总数: 88/88 PASS');
"

