ToolUse.name:
node -e "
// Validate sub-task A coordination
const { RoomStateMachine, STATES } = require('./src/shared/room-state.js');

// 清单 1.3: 跟子任务 A 协调 (不冲突)
// 子任务 A 加了 exitRoom / destroyed / exitBtn — 验证这些还在
const fs = require('fs');
const app = fs.readFileSync('src/client/app.js', 'utf8');
console.log('A.1 destroyed 守卫保留:', /this\.destroyed\s*=\s*true/.test(app));
console.log('A.2 destroyed 检查:', /if\s*\(\s*this\.destroyed\s*\)\s*return/.test(app));
console.log('A.3 exitRoom 函数:', /function exitRoom\(/.test(app));
console.log('A.4 exitBtn 绑定:', /exitBtn\.addEventListener\('click',\s*exitRoom\)/.test(app));
console.log('A.5 attemptReconnect 流程保留:', /function attemptReconnect/.test(app));

// 清单 5.1+5.2: 单测覆盖
const rsTest = fs.readFileSync('test/unit/room-state.test.js', 'utf8');
const vmTest = fs.readFileSync('test/unit/video-match.test.js', 'utf8');
const rsCount = (rsTest.match(/^\s*test\(/gm) || []).length;
const vmCount = (vmTest.match(/^\s*test\(/gm) || []).length;
console.log('room-state test() 数:', rsCount, '(期望 ≥32)');
console.log('video-match test() 数:', vmCount, '(期望 ≥28)');

// 清单 3.2: 匹配时无 UI 提示 (STATE_DISPLAY.IN_ROOM_SYNCED.mismatch = false)
const sm = new RoomStateMachine();
console.log('IN_ROOM_SYNCED canSync (期望 true):', sm._forceState(STATES.IN_ROOM_SYNCED) === undefined && sm.state === STATES.IN_ROOM_SYNCED);
sm.setState(STATES.CONNECTING);  // 合法
sm.setState(STATES.IN_ROOM_NO_VIDEO);
sm.setState(STATES.IN_ROOM_WAITING_PEER_VIDEO);
sm.setState(STATES.IN_ROOM_SYNCED);
console.log('Full happy path: state =', sm.state, ', canSync =', sm.canSync());

// 清单 3.5: 不匹配时不同步 (state=in_room_mismatch 时 canSync = false)
sm.setState(STATES.IN_ROOM_MISMATCH);
console.log('Mismatch path: state =', sm.state, ', canSync =', sm.canSync());

// 清单 4.2: 平滑切换 (CSS transition + listener 同步)
const css = fs.readFileSync('src/client/style.css', 'utf8');
console.log('transition 0.2s ease:', css.includes('transition: all 0.2s ease'));
"

