1	// SyncPlay - 视频匹配检测 (v0.6 FR-3)
2	// 比较两端视频信息是否"同一视频" — 用于触发 in_room_synced / in_room_mismatch 状态.
3	//
4	// 匹配策略 (per REQUIREMENTS.md FR-3): URL + 文件名 + 时长 三重校验, 任一通过即匹配.
5	//   - URL 相同: https://example.com/foo.mp4 === https://example.com/foo.mp4
6	//   - 文件名相同: myvideo.mp4 === myvideo.mp4 (用于本地 blob: URL, blob URL 每次会话唯一)
7	//   - 时长差 < 1s: 浮点误差容忍
8	//
9	// 浏览器通过 window.SyncPlayVideoMatch 使用, Node 测试通过 require 使用.
10	
11	(function (root, factory) {
12	  if (typeof module === 'object' && module.exports) {
13	    module.exports = factory();
14	  } else {
15	    root.SyncPlayVideoMatch = factory();
16	  }
17	}(typeof self !== 'undefined' ? self : this, function () {
18	  'use strict';
19	
20	  /**
21	   * 比较两端视频信息是否匹配
22	   * @param {VideoInfo|null|undefined} a
23	   * @param {VideoInfo|null|undefined} b
24	   * @returns {boolean}
25	   */
26	  function videosMatch(a, b) {
27	    if (!a || !b) return false;
28	    if (a.loaded === false || b.loaded === false) return false;
29	
30	    // 优先级 1: URL (去掉 query/fragment 后比较更稳)
