content.Text:
1	// SyncPlay - 客户端核心逻辑
2	// 重构版本 v2: 修复同步状态机 + 漂移校准 + 断线重连
3	// v0.6 FR-3: 房间状态机重构 (6 态) + 解耦视频与房间 + 视频不匹配提示
4	
5	(function () {
6	  'use strict';
7	
8	  // 从独立模块加载 SyncEngine(浏览器通过 window.SyncPlay,Node 可直接 require)
9	  const { SyncEngine } = window.SyncPlay || {};
10	  // v0.6 FR-3: 房间状态机 + 视频匹配
11	  const { STATES: ROOM_STATES, RoomStateMachine } = window.SyncPlayRoomState || {};
12	  const { videosMatch, describeVideo, emptyVideoInfo } = window.SyncPlayVideoMatch || {};
13	
14	  // ============ 配置 ============
15	  const CONFIG = {
16	    // PeerJS 服务器地址(默认走官方公共服务器,可改为自建)
17	    PEER_HOST: '0.peerjs.com',
18	    PEER_PORT: 443,
19	    PEER_PATH: '/',
20	    PEER_SECURE: true,
21	
22	    // 重连参数
23	    RECONNECT_DELAY_MS: 2000,
24	    MAX_RECONNECT_ATTEMPTS: 5,
25	  };
26	
27	  // ============ ICE 服务器配置 ============
28	  // 📌 加载顺序(config 文件必须在 app.js 之前):
29	  //    1. config.local.js   (git 忽略,放真凭据,可选)
30	  //    2. config.template.js (占位符,必备)
31	  //    3. app.js            (本文件,读 window.SYNCPLAY_ICE_SERVERS)
32	  // 📌 如果两个 config 文件都加载失败(理论不应发生),用最后的兜底占位符
33	  //    这种情况下 TURN 中继不会工作,只能 STUN 直连。
34	  const ICE_SERVERS = window.SYNCPLAY_ICE_SERVERS || [
35	    { urls: 'stun:global.relay.metered.ca:80' },
36	    { urls: 'turn:global.relay.metered.ca:80',  username: '__TURN_USERNAME__', credential: '__TURN_CREDENTIAL__' },
37	    { urls: 'turn:global.relay.metered.ca:443', username: '__TURN_USERNAME__', credential: '__TURN_CREDENTIAL__' },
38	    { urls: 'turns:global.relay.metered.ca:443', username: '__TURN_USERNAME__', credential: '__TURN_CREDENTIAL__' },
39	  ];
40	
41	  // ============ 工具函数 ============
42	
43	  /** 用 crypto 生成房间号(密码学安全) */
44	  function generateRoomId() {
45	    if (window.crypto && window.crypto.randomUUID) {
46	      return 'room-' + window.crypto.randomUUID().split('-')[0];
47	    }
48	    return 'room-' + Math.random().toString(36).substring(2, 10);
49	  }
50	
51	  /** Toast 通知(替代 alert) */
52	  function toast(msg, type = 'info') {
53	    let el = document.getElementById('toast');
54	    if (!el) {
55	      el = document.createElement('div');
56	      el.id = 'toast';
57	      el.className = 'toast';
58	      document.body.appendChild(el);
59	    }
60	    el.textContent = msg;
61	    el.className = 'toast show ' + type;
62	    clearTimeout(toast._t);
63	    toast._t = setTimeout(() => {
64	      el.className = 'toast';
65	    }, 3000);
66	  }
67	
68	  function updateLocalStatus(text, state) {
69	    document.getElementById('localStatus').textContent = text;
70	    document.getElementById('localStatusDot').className = 'status-dot ' + state;
71	  }
72	
73	  function updateRemoteStatus(text, state) {
74	    document.getElementById('remoteStatus').textContent = text;
75	    document.getElementById('remoteStatusDot').className = 'status-dot ' + state;
76	  }
77	
78	  /** 把 HTMLMediaElement.error.code 翻成人话 (FR-2 错误提示)
79	   *  1=ABORTED  2=NETWORK (CORS/断网)  3=DECODE (格式/损坏)  4=SRC_NOT_SUPPORTED
80	   */
81	  function describeVideoError(err) {
82	    if (!err) return '未知错误';
83	    switch (err.code) {
